def _default_video_roi_profile_for_game(game_name: str) -> str:
    key = str(game_name or "").strip().lower().replace(" ", "_").replace("'", "")
    if key in VIDEO_ROI_GAME_PROFILE_MAP:
        return VIDEO_ROI_GAME_PROFILE_MAP[key]
    lowered = str(game_name or "").strip().lower()
    if "firered" in lowered or "fire red" in lowered or "leafgreen" in lowered or "leaf green" in lowered:
        return "FireRed / LeafGreen"
    if "emerald" in lowered:
        return "Emerald"
    if "ruby" in lowered or "sapphire" in lowered:
        return "Ruby / Sapphire"
    if "gold" in lowered or "silver" in lowered or "crystal" in lowered:
        return "Gen 2 (G/S/C)"
    return "Generic Battle"


def _normalize_roi_preset_payload(raw: object) -> Optional[Dict[str, str]]:
    if not isinstance(raw, dict):
        return None
    ocr = str(raw.get("ocr_roi") or "").strip()
    sprite = str(raw.get("sprite_roi") or "").strip()
    shiny = str(raw.get("shiny_roi") or "").strip()
    if not (ocr and sprite and shiny):
        return None
    return {
        "ocr_roi": ocr,
        "sprite_roi": sprite,
        "shiny_roi": shiny,
    }



def _default_video_nameplate_roi_for_game(game_name: str) -> str:
    profile = _default_video_roi_profile_for_game(game_name)
    return str(VIDEO_NAMEPLATE_ROI_PRESETS.get(profile) or VIDEO_NAMEPLATE_ROI_PRESETS["Generic Battle"])
def _coerce_bool(value: object, default: bool = False) -> bool:
    if isinstance(value, bool):
        return bool(value)
    if isinstance(value, (int, float)):
        return bool(int(value))
    text = str(value or "").strip().lower()
    if text in {"1", "true", "yes", "on", "enabled"}:
        return True
    if text in {"0", "false", "no", "off", "disabled"}:
        return False
    return bool(default)


def _is_supported_video_game_name(game_name: str) -> bool:
    lowered = str(game_name or "").strip().lower()
    if not lowered:
        return False
    canonical = lowered.replace("version", "").replace("pokemon", "").strip()
    markers = (
        "firered", "fire red", "leafgreen", "leaf green",
        "emerald", "ruby", "sapphire",
        "gold", "silver", "crystal",
        "red", "blue", "yellow",
        "x", "y",
    )
    if any(marker == canonical or marker in lowered for marker in markers):
        return True
    return lowered.startswith("pokemon ")

LOGGER = logging.getLogger("pokeachieve_tracker")
if not LOGGER.handlers:
    _handler = logging.StreamHandler()
    _handler.setFormatter(
        logging.Formatter(
            "%(asctime)s.%(msecs)03d | %(levelname)-7s | %(message)s",
            datefmt="%Y-%m-%d %H:%M:%S",
        )
    )
    LOGGER.addHandler(_handler)
LOGGER.setLevel(logging.INFO)


def _format_log_fields(fields: Dict[str, object]) -> str:
    parts: List[str] = []
    for key in sorted(fields.keys()):
        value = fields.get(key)
        rendered = json.dumps(value, default=str, ensure_ascii=False, sort_keys=True)
        parts.append(f"{key}={rendered}")
    return " | ".join(parts)


def log_event(log_level: int, event: str, **fields):
    """Structured logging helper."""
    if fields:
        LOGGER.log(log_level, "%s | %s", event, _format_log_fields(fields))
    else:
        LOGGER.log(log_level, "%s", event)




